import React, { useState, useEffect } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [filter, setFilter] = useState('');
    const [sortField, setSortField] = useState('name');
    const [sortOrder, setSortOrder] = useState('asc');

    // Filter function
    const filteredRecords = records.filter(record => {
        const lowerCaseName = record.name.toLowerCase();
        const lowerCaseFilter = filter.toLowerCase();
        return lowerCaseName.includes(lowerCaseFilter);
    });

    // Sort function
    const sortedRecords = [...filteredRecords].sort((a, b) => {
        const field = sortField;
        const valueA = a[field];
        const valueB = b[field];

        if (sortOrder === 'asc') {
            return valueA > valueB ? 1 : -1;
        } else {
            return valueA < valueB ? 1 : -1;
        }
    });

    // Update records on filter or sort changes
    useEffect(() => {
        setRecords(sortedRecords);
    }, [filter, sortField, sortOrder, sortedRecords]);

    // Handle filter change
    const handleFilterChange = (e) => {
        setFilter(e.target.value);
    };

    // Handle sort change
    const handleSortChange = (e) => {
        setSortField(e.target.value);
        setSortOrder(e.target.value === 'asc' ? 'desc' : 'asc');
    };

    return (
        <div>
            <div>
                <input
                    type="text"
                    placeholder="Filter by name..."
                    value={filter}
                    onChange={handleFilterChange}
                />
                <select value={sortField} onChange={handleSortChange}>
                    <option value="name">name</option>
                    <option value="age">age</option>
                </select>
                <select value={sortOrder} onChange={handleSortChange}>
